public boolean twoTwo(int[] nums)
{

}

Code:
public boolean twoTwo(int[] nums) {
    int count = 0;
    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 2) {
            count++;
            if (i > 0 && nums[i - 1] != 2) {
                return false;
            }
        }
    }
    return count == 0 || count == nums.length;
}

